56	// ── Canonical-fixture identities ─────────────────────────────
57	
58	/// Canonical RBRR prefix bases installed by case 1. Distinct from pristine's
59	/// throwaway prefix bases (prlc/prlr); per-station tincture from BURS is
60	/// composed in at runtime so parallel-station runs land in disjoint cloud
61	/// names. Case 2's probe detects canonical state by reading the moniker's
62	/// family stem (also tinctured) from rbrr.env.
63	pub(crate) const RBTDRK_CANONICAL_CLOUD_BASE: &str = "canc";
64	pub(crate) const RBTDRK_CANONICAL_RUNTIME_BASE: &str = "canr";
65	
66	/// Family-stem base for canonical depots; six-digit auto-increment suffix per
67	/// run. Depots persist post-success for operator inspection; reruns pick the
68	/// next free suffix by walking depot_list output. Per-station tincture is
69	/// composed in at runtime so each station's monikers fact-file-walk against
70	/// a disjoint family stem. Era-bumped past `canest` and `canest2` to
71	/// side-step pending-delete projectId reservations from burned-bridges
72	/// teardown. The `canest2` bump was forced when the prior gmail-identity
73	/// payor's deleted `canest2bhm100000` depot held the global projectId in
74	/// DELETE_REQUESTED: project IDs are globally unique and reserved ~30 days
75	/// post-delete, and the active-only, single-identity allocator re-derives a
76	/// reserved ID it can neither see nor own.
77	pub(crate) const RBTDRK_FAMILY_STEM_BASE: &str = "canest3";
78	
79	/// Static identities for the canonical SA cycle. Stable across runs because
80	/// each run uses a fresh canest depot project.
81	const RBTDRK_IDENTITY_RETRIEVER: &str = "canest-ret";
82	const RBTDRK_IDENTITY_DIRECTOR: &str = "canest-dir";
83	
84	const RBTDRK_FAMILY_NUMERIC_FLOOR: u32 = 100000;
85	const RBTDRK_FAMILY_NUMERIC_WIDTH: usize = 6;
86	
87	// rbgp_depot_list emits fact files at
88	// `<cloud_prefix>/<moniker>.depot` (state) and
89	// `<cloud_prefix>/<moniker>.depot-project` (project_id). The cloud_prefix
90	// subdir prevents collisions between same-moniker depots under different
91	// cloud_prefixes.
92	const RBTDRK_FACT_EXT_DEPOT: &str = "depot";
93	const RBTDRK_FACT_EXT_DEPOT_PROJECT: &str = "depot-project";
94	const RBTDRK_FACT_GOVERNOR_SA_EMAIL: &str = "rbgp_fact_governor_sa_email";
95	
96	const RBTDRK_FIELD_RBRD_CLOUD_PREFIX: &str = "RBRD_CLOUD_PREFIX";
97	const RBTDRK_FIELD_RBRR_RUNTIME_PREFIX: &str = "RBRR_RUNTIME_PREFIX";
98	const RBTDRK_FIELD_RBRD_DEPOT_MONIKER: &str = "RBRD_DEPOT_MONIKER";
99	const RBTDRK_FIELD_RBRR_SECRETS_DIR: &str = "RBRR_SECRETS_DIR";
100	
101	// Bundled moorings paths, composed from the crate-canonical moorings dir.
102	const RBTDRK_RBRR_FILE: &str = concat!(crate::rbtd_moorings_dir!(), "/rbrr.env");
103	const RBTDRK_RBRD_FILE: &str = concat!(crate::rbtd_moorings_dir!(), "/rbrd.env");
104	const RBTDRK_RBRA_FILE: &str = "rbra.env";
105	
106	/// BURS station-file env var (exported by bul_launcher.sh) — absolute path
107	/// to the developer's burs.env. Source for BURS_TINCTURE.
108	const RBTDRK_ENV_STATION_FILE: &str = "BURD_STATION_FILE";
109	
110	/// Read BURS_TINCTURE from the station file resolved via BURD_STATION_FILE.
111	/// BURS validation upstream (zburs_enforce) guarantees the value is 1-3 chars
112	/// of lowercase alphanumeric starting with a letter.
113	pub(crate) fn rbtdrk_burs_tincture() -> Result<String, String> {
114	    let path_str = std::env::var(RBTDRK_ENV_STATION_FILE)
115	        .map_err(|_| format!("{} not set in environment", RBTDRK_ENV_STATION_FILE))?;
116	    let path = PathBuf::from(&path_str);
117	    rbtdrk_read_env_value(&path, "BURS_TINCTURE")
118	        .ok_or_else(|| format!("BURS_TINCTURE not in {}", path.display()))
119	}
120	
121	/// Compose canonical RBRD_CLOUD_PREFIX with the given tincture.
122	pub(crate) fn rbtdrk_canonical_cloud_prefix(tincture: &str) -> String {
123	    format!("{}{}-", RBTDRK_CANONICAL_CLOUD_BASE, tincture)
124	}
125	
126	/// Compose canonical RBRR_RUNTIME_PREFIX with the given tincture.
127	pub(crate) fn rbtdrk_canonical_runtime_prefix(tincture: &str) -> String {
128	    format!("{}{}-", RBTDRK_CANONICAL_RUNTIME_BASE, tincture)
129	}
130	
131	/// Compose canonical family stem with the given tincture.
132	pub(crate) fn rbtdrk_family_stem(tincture: &str) -> String {
133	    format!("{}{}", RBTDRK_FAMILY_STEM_BASE, tincture)
134	}
