136	// ── Helpers ──────────────────────────────────────────────────
137	
138	/// Read an env-file value or None if absent. Mirrors pristine's helper —
139	/// kept local to avoid coupling canonical-establish to pristine-lifecycle.
140	fn rbtdrk_read_env_value(path: &Path, key: &str) -> Option<String> {
141	    let content = std::fs::read_to_string(path).ok()?;
142	    let prefix = format!("{}=", key);
143	    for line in content.lines() {
144	        let trimmed = line.trim_start();
145	        if trimmed.starts_with('#') {
146	            continue;
147	        }
148	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
149	            return Some(rest.to_string());
150	        }
151	    }
152	    None
153	}
154	
155	fn rbtdrk_resolve(root: &Path, raw: &str) -> PathBuf {
156	    if Path::new(raw).is_absolute() {
157	        PathBuf::from(raw)
158	    } else {
159	        root.join(raw)
160	    }
161	}
162	
163	fn rbtdrk_replace_env_fields(content: &str, pairs: &[(&str, &str)]) -> String {
164	    let mut result: String = content
165	        .lines()
166	        .map(|line| {
167	            for (key, value) in pairs {
168	                let assign = format!("{}=", key);
169	                if line.starts_with(&assign) {
170	                    return format!("{}{}", assign, value);
171	                }
172	            }
173	            line.to_string()
174	        })
175	        .collect::<Vec<_>>()
176	        .join("\n");
177	    if content.ends_with('\n') {
178	        result.push('\n');
179	    }
180	    result
181	}
182	
183	fn rbtdrk_git_add_and_commit(root: &Path, file: &str, message: &str) -> Result<(), String> {
184	    rbtdrk_git_add_and_commit_paths(root, &[file], message)
185	}
186	
187	fn rbtdrk_git_add_and_commit_paths(
188	    root: &Path,
189	    files: &[&str],
190	    message: &str,
191	) -> Result<(), String> {
192	    let mut add_args: Vec<&str> = vec!["add"];
193	    add_args.extend_from_slice(files);
194	    let add = Command::new("git")
195	        .args(&add_args)
196	        .current_dir(root)
197	        .output()
198	        .map_err(|e| format!("rbtdrk: git add invocation failed: {}", e))?;
199	    if !add.status.success() {
200	        return Err(format!(
201	            "rbtdrk: git add failed (exit {}): {}",
202	            add.status.code().unwrap_or(-1),
203	            String::from_utf8_lossy(&add.stderr).trim()
204	        ));
205	    }
206	    let commit = Command::new("git")
207	        .args(["commit", "-m", message])
208	        .current_dir(root)
209	        .output()
210	        .map_err(|e| format!("rbtdrk: git commit invocation failed: {}", e))?;
211	    if !commit.status.success() {
212	        return Err(format!(
213	            "rbtdrk: git commit failed (exit {}): {}",
214	            commit.status.code().unwrap_or(-1),
215	            String::from_utf8_lossy(&commit.stderr).trim()
216	        ));
217	    }
218	    Ok(())
219	}
220	
221	/// Resolve canonical RBRA path for a role: <RBRR_SECRETS_DIR>/<role>/rbra.env.
222	pub(crate) fn rbtdrk_canonical_rbra(root: &Path, role: &str) -> Result<PathBuf, String> {
223	    let rbrr = root.join(RBTDRK_RBRR_FILE);
224	    let secrets_dir = rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_SECRETS_DIR)
225	        .ok_or_else(|| format!("RBRR_SECRETS_DIR missing from {}", rbrr.display()))?;
226	    if secrets_dir.is_empty() {
227	        return Err(format!("RBRR_SECRETS_DIR is blank in {}", rbrr.display()));
228	    }
229	    Ok(rbtdrk_resolve(root, &secrets_dir)
230	        .join(role)
231	        .join(RBTDRK_RBRA_FILE))
232	}
233	
234	// ── Canonical-prefix install (case 1) ───────────────────────
235	
236	/// Idempotently install canc-/canr- prefixes. CLOUD_PREFIX lands in rbrd.env,
237	/// RUNTIME_PREFIX lands in rbrr.env. Returns Ok without committing when both
238	/// already match the canonical markers; otherwise rewrites both files and
239	/// commits in one go.
240	pub(crate) fn rbtdrk_install_canonical_prefixes(root: &Path) -> Result<(), String> {
241	    let rbrr = root.join(RBTDRK_RBRR_FILE);
242	    let rbrd = root.join(RBTDRK_RBRD_FILE);
243	    let tincture = rbtdrk_burs_tincture()?;
244	    let cloud_target = rbtdrk_canonical_cloud_prefix(&tincture);
245	    let runtime_target = rbtdrk_canonical_runtime_prefix(&tincture);
246	
247	    let cloud = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX).unwrap_or_default();
248	    let runtime =
249	        rbtdrk_read_env_value(&rbrr, RBTDRK_FIELD_RBRR_RUNTIME_PREFIX).unwrap_or_default();
250	    if cloud == cloud_target && runtime == runtime_target {
251	        return Ok(());
252	    }
253	
254	    if cloud != cloud_target {
255	        let content = std::fs::read_to_string(&rbrd)
256	            .map_err(|e| format!("rbtdrk: read {}: {}", rbrd.display(), e))?;
257	        let new_content = rbtdrk_replace_env_fields(
258	            &content,
259	            &[(RBTDRK_FIELD_RBRD_CLOUD_PREFIX, cloud_target.as_str())],
260	        );
261	        std::fs::write(&rbrd, &new_content)
262	            .map_err(|e| format!("rbtdrk: write {}: {}", rbrd.display(), e))?;
263	    }
264	
265	    if runtime != runtime_target {
266	        let content = std::fs::read_to_string(&rbrr)
267	            .map_err(|e| format!("rbtdrk: read {}: {}", rbrr.display(), e))?;
268	        let new_content = rbtdrk_replace_env_fields(
269	            &content,
270	            &[(RBTDRK_FIELD_RBRR_RUNTIME_PREFIX, runtime_target.as_str())],
271	        );
272	        std::fs::write(&rbrr, &new_content)
273	            .map_err(|e| format!("rbtdrk: write {}: {}", rbrr.display(), e))?;
274	    }
275	
276	    let commit_msg = format!(
277	        "canonical-establish fixture: install canonical prefixes ({}/{})",
278	        cloud_target, runtime_target
279	    );
280	    rbtdrk_git_add_and_commit_paths(
281	        root,
282	        &[RBTDRK_RBRR_FILE, RBTDRK_RBRD_FILE],
283	        &commit_msg,
284	    )
285	}
286	
287	fn rbtdrk_install_depot_moniker(root: &Path, moniker: &str) -> Result<(), String> {
288	    let rbrd = root.join(RBTDRK_RBRD_FILE);
289	    let content = std::fs::read_to_string(&rbrd)
290	        .map_err(|e| format!("rbtdrk: read {}: {}", rbrd.display(), e))?;
291	    let new_content =
292	        rbtdrk_replace_env_fields(&content, &[(RBTDRK_FIELD_RBRD_DEPOT_MONIKER, moniker)]);
293	    std::fs::write(&rbrd, &new_content)
294	        .map_err(|e| format!("rbtdrk: write {}: {}", rbrd.display(), e))?;
295	    let commit_msg = format!(
296	        "canonical-establish fixture: set {}={}",
297	        RBTDRK_FIELD_RBRD_DEPOT_MONIKER, moniker
298	    );
299	    rbtdrk_git_add_and_commit(root, RBTDRK_RBRD_FILE, &commit_msg)
300	}
