302	/// Compose depot project_id from kindled regime values: <CLOUD>d-<moniker>.
303	fn rbtdrk_compose_project_id(root: &Path, moniker: &str) -> Result<String, String> {
304	    let rbrd = root.join(RBTDRK_RBRD_FILE);
305	    let cloud_prefix = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX)
306	        .ok_or_else(|| format!("RBRD_CLOUD_PREFIX missing from {}", rbrd.display()))?;
307	    Ok(format!("{}d-{}", cloud_prefix, moniker))
308	}
309	
310	/// Cloud-prefix subdir name used in depot fact-file layout
311	/// (`<cloud_prefix>/<moniker>.depot`). Derived from RBRD_CLOUD_PREFIX with
312	/// the structural trailing `-` stripped so it matches the filesystem layout
313	/// emitted by zrbgp_depot_state_emit.
314	fn rbtdrk_cloud_prefix_subdir(root: &Path) -> Result<String, String> {
315	    let rbrd = root.join(RBTDRK_RBRD_FILE);
316	    let cloud_prefix = rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_CLOUD_PREFIX)
317	        .ok_or_else(|| format!("RBRD_CLOUD_PREFIX missing from {}", rbrd.display()))?;
318	    Ok(cloud_prefix.trim_end_matches('-').to_string())
319	}
320	
321	/// Pick the next free moniker for `family_stem` by walking the depot_list
322	/// invocation's BURV output dir for `<family>NNNNNN.depot` files under the
323	/// current cloud_prefix subdir. Returns
324	/// `<family>RBTDRK_FAMILY_NUMERIC_FLOOR` when no matching files exist.
325	/// Restricting the walk to the current cloud_prefix is what makes allocation
326	/// collision-safe: a same-numbered moniker under a foreign cloud_prefix is
327	/// correctly ignored.
328	///
329	/// Caller contract: `list_result` MUST be from a freshly-invoked depot_list
330	/// that ran in the current process. The fact-file scan IS the collision
331	/// check — stale state means picking a colliding moniker. Do not reuse a
332	/// `list_result` across cases or pass an operator-cached value.
333	fn rbtdrk_pick_next_moniker(
334	    list_result: &rbtdri_InvokeResult,
335	    root: &Path,
336	    family_stem: &str,
337	) -> Result<String, String> {
338	    let prefix_dir = rbtdrk_cloud_prefix_subdir(root)?;
339	    let dir = list_result
340	        .burv_output
341	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
342	        .join(&prefix_dir);
343	    let entries = match std::fs::read_dir(&dir) {
344	        Ok(e) => e,
345	        Err(_) => {
346	            return Ok(format!("{}{}", family_stem, RBTDRK_FAMILY_NUMERIC_FLOOR));
347	        }
348	    };
349	    let suffix_ext = format!(".{}", RBTDRK_FACT_EXT_DEPOT);
350	    let mut max_suffix: Option<u32> = None;
351	    for entry in entries.flatten() {
352	        let name = match entry.file_name().into_string() {
353	            Ok(n) => n,
354	            Err(_) => continue,
355	        };
356	        let stem = match name.strip_suffix(&suffix_ext) {
357	            Some(s) => s,
358	            None => continue,
359	        };
360	        let numeric = match stem.strip_prefix(family_stem) {
361	            Some(s) => s,
362	            None => continue,
363	        };
364	        if numeric.len() != RBTDRK_FAMILY_NUMERIC_WIDTH {
365	            continue;
366	        }
367	        let parsed: u32 = match numeric.parse() {
368	            Ok(n) => n,
369	            Err(_) => continue,
370	        };
371	        max_suffix = Some(max_suffix.map_or(parsed, |m| m.max(parsed)));
372	    }
373	    let next = match max_suffix {
374	        Some(m) => m + 1,
375	        None => RBTDRK_FAMILY_NUMERIC_FLOOR,
376	    };
377	    Ok(format!("{}{}", family_stem, next))
378	}
