380	fn rbtdrk_invoke_logged(
381	    ctx: &mut rbtdri_Context,
382	    colophon: &str,
383	    args: &[&str],
384	    extra_env: &[(&str, &str)],
385	    dir: &Path,
386	    label: &str,
387	) -> Result<rbtdri_InvokeResult, String> {
388	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
389	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
390	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
391	    Ok(result)
392	}
