394	// ── Probes ───────────────────────────────────────────────────
395	
396	/// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
397	/// have no context, so they read the project root from current_dir() — theurge
398	/// always launches from the project root.
399	fn rbtdrk_probe_root() -> Result<PathBuf, String> {
400	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
401	}
402	
403	/// Case 1 probe: rbrr.env exists. Sanity precondition — canonical-establish
404	/// presumes the regime has been initialized at least to the marshal-zero
405	/// blank-template shape.
406	fn rbtdrk_probe_rbrr_present() -> Result<(), String> {
407	    let root = rbtdrk_probe_root()?;
408	    let rbrr = root.join(RBTDRK_RBRR_FILE);
409	    if !rbrr.exists() {
410	        return Err(format!("rbrr.env not found at {}", rbrr.display()));
411	    }
412	    Ok(())
413	}
414	
415	/// Case 2 probe: canonical depot moniker installed in rbrd.env. Established
416	/// by case 1; absence means depot-levy didn't run or rbrd.env was rewritten.
417	fn rbtdrk_probe_canonical_moniker() -> Result<(), String> {
418	    let root = rbtdrk_probe_root()?;
419	    let rbrd = root.join(RBTDRK_RBRD_FILE);
420	    let tincture = rbtdrk_burs_tincture()?;
421	    let family_stem = rbtdrk_family_stem(&tincture);
422	    let moniker =
423	        rbtdrk_read_env_value(&rbrd, RBTDRK_FIELD_RBRD_DEPOT_MONIKER).unwrap_or_default();
424	    if !moniker.starts_with(&family_stem) {
425	        return Err(format!(
426	            "{}={:?} does not begin with '{}' — canonical depot moniker not installed",
427	            RBTDRK_FIELD_RBRD_DEPOT_MONIKER, moniker, family_stem
428	        ));
429	    }
430	    Ok(())
431	}
432	
433	/// Cases 3 and 4 probe: governor RBRA file present at the canonical path.
434	/// Established by case 2's mantle + canonical-copy step.
435	fn rbtdrk_probe_governor_rbra() -> Result<(), String> {
436	    let root = rbtdrk_probe_root()?;
437	    let path = rbtdrk_canonical_rbra(&root, RBTDRM_ROLE_GOVERNOR)?;
438	    if !path.exists() {
439	        return Err(format!("governor RBRA absent at {}", path.display()));
440	    }
441	    Ok(())
442	}
443	
444	// ── Cases ────────────────────────────────────────────────────
445	
446	/// Case 1 — canonical depot levy. Installs canc-/canr- prefixes, picks a
447	/// fresh canest moniker, levies the depot, cross-checks project_id from
448	/// fact-file against the RBDC compose derivation.
449	fn rbtdrk_depot_levy(dir: &Path) -> rbtdre_Verdict {
450	    let probe = rbtdrb_Probe {
451	        name: "rbrr.env present",
452	        check: rbtdrk_probe_rbrr_present,
453	        remediation: "ensure regime is initialized — rerun pristine-lifecycle if needed",
454	    };
455	    if let Err(v) = rbtdrb_assert(&probe) {
456	        return v;
457	    }
458	    rbtdrc_with_ctx(|ctx| rbtdrk_depot_levy_impl(ctx, dir))
459	}
460	
461	fn rbtdrk_depot_levy_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
462	    let root = ctx.project_root().to_path_buf();
463	
464	    if let Err(e) = rbtdrk_install_canonical_prefixes(&root) {
465	        return rbtdre_Verdict::Fail(format!("install canonical prefixes: {}", e));
466	    }
467	
468	    let list_pre = match rbtdrk_invoke_logged(
469	        ctx,
470	        RBTDRM_COLOPHON_DEPOT_LIST,
471	        &[],
472	        &[],
473	        dir,
474	        "list-pre",
475	    ) {
476	        Ok(r) => r,
477	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (pre-levy): {}", e)),
478	    };
479	    if list_pre.exit_code != 0 {
480	        return rbtdre_Verdict::Fail(format!(
481	            "depot list (pre-levy) exit {}\n{}",
482	            list_pre.exit_code, list_pre.stderr
483	        ));
484	    }
485	
486	    let tincture = match rbtdrk_burs_tincture() {
487	        Ok(t) => t,
488	        Err(e) => return rbtdre_Verdict::Fail(format!("read BURS_TINCTURE: {}", e)),
489	    };
490	    let family_stem = rbtdrk_family_stem(&tincture);
491	    let moniker = match rbtdrk_pick_next_moniker(&list_pre, &root, &family_stem) {
492	        Ok(m) => m,
493	        Err(e) => return rbtdre_Verdict::Fail(format!("pick next moniker: {}", e)),
494	    };
495	    if let Err(e) = rbtdrk_install_depot_moniker(&root, &moniker) {
496	        return rbtdre_Verdict::Fail(format!("install depot moniker: {}", e));
497	    }
498	
499	    let levy = match rbtdrk_invoke_logged(
500	        ctx,
501	        RBTDRM_COLOPHON_DEPOT_LEVY,
502	        &[],
503	        &[],
504	        dir,
505	        "levy",
506	    ) {
507	        Ok(r) => r,
508	        Err(e) => return rbtdre_Verdict::Fail(format!("depot levy: {}", e)),
509	    };
510	    if levy.exit_code != 0 {
511	        return rbtdre_Verdict::Fail(format!(
512	            "depot levy exit {}\n{}",
513	            levy.exit_code, levy.stderr
514	        ));
515	    }
516	
517	    let list_present = match rbtdrk_invoke_logged(
518	        ctx,
519	        RBTDRM_COLOPHON_DEPOT_LIST,
520	        &[],
521	        &[],
522	        dir,
523	        "list-present",
524	    ) {
525	        Ok(r) => r,
526	        Err(e) => return rbtdre_Verdict::Fail(format!("depot list (after levy): {}", e)),
527	    };
528	    if list_present.exit_code != 0 {
529	        return rbtdre_Verdict::Fail(format!(
530	            "depot list (after levy) exit {}\n{}",
531	            list_present.exit_code, list_present.stderr
532	        ));
533	    }
534	
535	    let prefix_dir = match rbtdrk_cloud_prefix_subdir(&root) {
536	        Ok(p) => p,
537	        Err(e) => return rbtdre_Verdict::Fail(format!("resolve cloud_prefix subdir: {}", e)),
538	    };
539	    let fact_path = list_present
540	        .burv_output
541	        .join(RBTDRI_BURV_OUTPUT_SUBDIR)
542	        .join(&prefix_dir)
543	        .join(format!("{}.{}", moniker, RBTDRK_FACT_EXT_DEPOT_PROJECT));
544	    let fact_project_id = match std::fs::read_to_string(&fact_path) {
545	        Ok(s) => s.trim().to_string(),
546	        Err(e) => {
547	            return rbtdre_Verdict::Fail(format!(
548	                "read depot-project fact '{}': {}",
549	                fact_path.display(),
550	                e
551	            ))
552	        }
553	    };
554	    if fact_project_id.is_empty() {
555	        return rbtdre_Verdict::Fail(format!(
556	            "depot-project fact is empty: {}",
557	            fact_path.display()
558	        ));
559	    }
560	    let _ = std::fs::write(dir.join("project-id.txt"), &fact_project_id);
561	
562	    let composed = match rbtdrk_compose_project_id(&root, &moniker) {
563	        Ok(p) => p,
564	        Err(e) => return rbtdre_Verdict::Fail(format!("compose project_id: {}", e)),
565	    };
566	    if composed != fact_project_id {
567	        return rbtdre_Verdict::Fail(format!(
568	            "project_id mismatch: RBDC compose='{}' vs depot-list fact='{}' \
569	             (RBDC kindle derivation diverged from payor creation)",
570	            composed, fact_project_id
571	        ));
572	    }
573	    rbtdre_Verdict::Pass
574	}
575	
576	/// Case 2 — governor mantle. Mantles governor against the canonical depot,
577	/// reads the SA email fact, copies governor RBRA from BURV output to the
578	/// canonical path under RBRR_SECRETS_DIR.
579	fn rbtdrk_governor_mantle(dir: &Path) -> rbtdre_Verdict {
580	    let probe = rbtdrb_Probe {
581	        name: "canonical depot moniker installed",
582	        check: rbtdrk_probe_canonical_moniker,
583	        remediation: "rerun rbtdrk_depot_levy or the full canonical-establish fixture",
584	    };
585	    if let Err(v) = rbtdrb_assert(&probe) {
586	        return v;
587	    }
588	    rbtdrc_with_ctx(|ctx| rbtdrk_governor_mantle_impl(ctx, dir))
589	}
590	
591	fn rbtdrk_governor_mantle_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
592	    let root = ctx.project_root().to_path_buf();
593	
594	    let assay = match rbtdrk_canonical_rbra(&root, "assay") {
595	        Ok(p) => p,
596	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
597	    };
598	
599	    let mantle = match rbtdrk_invoke_logged(
600	        ctx,
601	        RBTDRM_COLOPHON_GOV_MANTLE,
602	        &[],
603	        &[],
604	        dir,
605	        "mantle",
606	    ) {
607	        Ok(r) => r,
608	        Err(e) => return rbtdre_Verdict::Fail(format!("governor mantle: {}", e)),
609	    };
610	    if mantle.exit_code != 0 {
611	        return rbtdre_Verdict::Fail(format!(
612	            "governor mantle exit {}\n{}",
613	            mantle.exit_code, mantle.stderr
614	        ));
615	    }
616	
617	    let email = match rbtdri_read_burv_fact(&mantle, RBTDRK_FACT_GOVERNOR_SA_EMAIL) {
618	        Ok(s) => s,
619	        Err(e) => return rbtdre_Verdict::Fail(format!("read governor SA email fact: {}", e)),
620	    };
621	    let _ = std::fs::write(dir.join("governor-sa-email.txt"), &email);
622	
623	    if !assay.exists() {
624	        return rbtdre_Verdict::Fail(format!(
625	            "assay RBRA absent after governor mantle: {}",
626	            assay.display()
627	        ));
628	    }
629	
630	    let canonical = match rbtdrk_canonical_rbra(&root, RBTDRM_ROLE_GOVERNOR) {
631	        Ok(p) => p,
632	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical governor RBRA path: {}", e)),
633	    };
634	    if let Some(parent) = canonical.parent() {
635	        if let Err(e) = std::fs::create_dir_all(parent) {
636	            return rbtdre_Verdict::Fail(format!(
637	                "create governor RBRA dir {}: {}",
638	                parent.display(),
639	                e
640	            ));
641	        }
642	    }
643	    if let Err(e) = std::fs::copy(&assay, &canonical) {
644	        return rbtdre_Verdict::Fail(format!(
645	            "copy assay RBRA → governor canonical {}: {}",
646	            canonical.display(),
647	            e
648	        ));
649	    }
650	    rbtdre_Verdict::Pass
651	}
652	
653	/// Case 3 — retriever invest + access-probe. The access-probe doubles as the
654	/// IAM-propagation gate: the invest tabtarget is responsible for waiting on
655	/// propagation before exiting (or the probe iterates internally). No separate
656	/// propagation-wait case.
657	fn rbtdrk_retriever_invest(dir: &Path) -> rbtdre_Verdict {
658	    let probe = rbtdrb_Probe {
659	        name: "governor RBRA present",
660	        check: rbtdrk_probe_governor_rbra,
661	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
662	    };
663	    if let Err(v) = rbtdrb_assert(&probe) {
664	        return v;
665	    }
666	    rbtdrc_with_ctx(|ctx| {
667	        rbtdrk_role_invest_impl(
668	            ctx,
669	            dir,
670	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
671	            RBTDRK_IDENTITY_RETRIEVER,
672	            RBTDRM_ROLE_RETRIEVER,
673	        )
674	    })
675	}
676	
677	/// Case 4 — director invest + access-probe.
678	fn rbtdrk_director_invest(dir: &Path) -> rbtdre_Verdict {
679	    let probe = rbtdrb_Probe {
680	        name: "governor RBRA present",
681	        check: rbtdrk_probe_governor_rbra,
682	        remediation: "rerun rbtdrk_governor_mantle or the full canonical-establish fixture",
683	    };
684	    if let Err(v) = rbtdrb_assert(&probe) {
685	        return v;
686	    }
687	    rbtdrc_with_ctx(|ctx| {
688	        rbtdrk_role_invest_impl(
689	            ctx,
690	            dir,
691	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
692	            RBTDRK_IDENTITY_DIRECTOR,
693	            RBTDRM_ROLE_DIRECTOR,
694	        )
695	    })
696	}
697	
698	/// Shared invest body for retriever and director: invest → assert assay
699	/// dropped by the invest tabtarget → copy to canonical role path → access-probe.
700	fn rbtdrk_role_invest_impl(
701	    ctx: &mut rbtdri_Context,
702	    dir: &Path,
703	    invest_colophon: &str,
704	    identity: &str,
705	    role: &str,
706	) -> rbtdre_Verdict {
707	    let root = ctx.project_root().to_path_buf();
708	
709	    let assay = match rbtdrk_canonical_rbra(&root, "assay") {
710	        Ok(p) => p,
711	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical assay RBRA path: {}", e)),
712	    };
713	
714	    let label_invest = format!("invest-{}", role);
715	    let invest = match rbtdrk_invoke_logged(
716	        ctx,
717	        invest_colophon,
718	        &[identity],
719	        &[],
720	        dir,
721	        &label_invest,
722	    ) {
723	        Ok(r) => r,
724	        Err(e) => return rbtdre_Verdict::Fail(format!("invest {}: {}", role, e)),
725	    };
726	    if invest.exit_code != 0 {
727	        return rbtdre_Verdict::Fail(format!(
728	            "invest {} exit {}\n{}",
729	            role, invest.exit_code, invest.stderr
730	        ));
731	    }
732	
733	    if !assay.exists() {
734	        return rbtdre_Verdict::Fail(format!(
735	            "assay RBRA absent after invest-{}: {}",
736	            role,
737	            assay.display()
738	        ));
739	    }
740	
741	    let canonical = match rbtdrk_canonical_rbra(&root, role) {
742	        Ok(p) => p,
743	        Err(e) => return rbtdre_Verdict::Fail(format!("canonical {} RBRA path: {}", role, e)),
744	    };
745	    if let Some(parent) = canonical.parent() {
746	        if let Err(e) = std::fs::create_dir_all(parent) {
747	            return rbtdre_Verdict::Fail(format!(
748	                "create {} RBRA dir {}: {}",
749	                role,
750	                parent.display(),
751	                e
752	            ));
753	        }
754	    }
755	    if let Err(e) = std::fs::copy(&assay, &canonical) {
756	        return rbtdre_Verdict::Fail(format!(
757	            "copy assay RBRA → {} canonical {}: {}",
758	            role,
759	            canonical.display(),
760	            e
761	        ));
762	    }
763	
764	    let probe_colophon = match rbtdrm_credential_check_colophon(role) {
765	        Some(c) => c,
766	        None => return rbtdre_Verdict::Fail(format!("unknown credential role: {}", role)),
767	    };
768	    let probe_result = match rbtdri_invoke_global(ctx, probe_colophon, &[], &[]) {
769	        Ok(r) => r,
770	        Err(e) => {
771	            return rbtdre_Verdict::Fail(format!("access-probe {} invocation: {}", role, e))
772	        }
773	    };
774	    let _ = std::fs::write(
775	        dir.join(format!("probe-{}-stdout.txt", role)),
776	        &probe_result.stdout,
777	    );
778	    let _ = std::fs::write(
779	        dir.join(format!("probe-{}-stderr.txt", role)),
780	        &probe_result.stderr,
781	    );
782	    if probe_result.exit_code != 0 {
783	        return rbtdre_Verdict::Fail(format!(
784	            "access-probe {} exit {}\n{}",
785	            role, probe_result.exit_code, probe_result.stderr
786	        ));
787	    }
788	
789	    rbtdre_Verdict::Pass
790	}
791	
792	// ── Section registry ─────────────────────────────────────────
793	
794	pub static RBTDRK_CASES_CANONICAL_ESTABLISH: &[rbtdre_Case] = &[
795	    case!(rbtdrk_depot_levy),
796	    case!(rbtdrk_governor_mantle),
797	    case!(rbtdrk_retriever_invest),
798	    case!(rbtdrk_director_invest),
799	];
800	
801	pub static RBTDRK_FIXTURE_CANONICAL_ESTABLISH: rbtdre_Fixture = rbtdre_Fixture {
802	    name: RBTDRM_FIXTURE_CANONICAL_ESTABLISH,
803	    disposition: rbtdre_Disposition::StateProgressing,
804	    setup: None,
805	    teardown: None,
806	    cases: RBTDRK_CASES_CANONICAL_ESTABLISH,
807	};
808	
809	// canonical-invest — the skirmish suite's no-levy variant. Reuses the three
810	// investiture case fns verbatim but omits `depot_levy`: skirmish runs against
811	// a depot the operator has levied by hand, so no GCP project is created per
812	// run. Each investiture case carries its own precondition probe (governor
813	// mantle probes the standing depot's moniker; the invests probe the governor),
814	// so the cases compose against an operator-levied depot exactly as they do
815	// after canonical-establish's case 1. Sharing the case fns is the same
816	// provenance-vs-behavior split tadmor/moriah exploit with RBTDRC_CASES_SECURITY.
817	pub static RBTDRK_CASES_CANONICAL_INVEST: &[rbtdre_Case] = &[
818	    case!(rbtdrk_governor_mantle),
819	    case!(rbtdrk_retriever_invest),
820	    case!(rbtdrk_director_invest),
821	];
822	
823	pub static RBTDRK_FIXTURE_CANONICAL_INVEST: rbtdre_Fixture = rbtdre_Fixture {
824	    name: RBTDRM_FIXTURE_CANONICAL_INVEST,
825	    disposition: rbtdre_Disposition::StateProgressing,
826	    setup: None,
827	    teardown: None,
828	    cases: RBTDRK_CASES_CANONICAL_INVEST,
829	};
